        };
        experience: {
            title: string;
            jobs: Experience[];
        };
        projects: {
            title: string;
            items: Project[];
        };
        education: {
            title: string;
            items: Education[];
        };
    };
    controls: {
        toggleTheme: string;
        toggleLanguage: string;
        download: string;
    };
}

